import{_ as a,c as n,a as e,o as i}from"./app-CEcM0piI.js";const t={};function l(d,s){return i(),n("div",null,s[0]||(s[0]=[e(`<h3 id="构造方法" tabindex="-1"><a class="header-anchor" href="#构造方法"><span>构造方法</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//创建空白字符串</span></span>
<span class="line"><span>public String()</span></span>
<span class="line"><span>//根据传入的字符串，创建字符串对象</span></span>
<span class="line"><span>public String(String original)</span></span>
<span class="line"><span>//根据字符数组，创建字符串对象</span></span>
<span class="line"><span>public String(char[] chs)</span></span>
<span class="line"><span>//根据字节数组，创建字符串对象</span></span>
<span class="line"><span>public String(byte[] chs)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//直接赋值的方式</span></span>
<span class="line"><span>String s=&quot;abc&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当使用双引号直接赋值时，系统会检查该字符串是否在串池中存在，如果不存在则创建新得，如果存在就复用，也就是字符串类型指针指向该字符串 而使用new创建出来的字符串不管有没有都会在堆内存中创建一个新的</p><p>比较运算符== 如果比较的时基本数据类型比较的都是数据值 如果是引用数据类型，因为引用数据类型中存的实际上是指向值的地址，因此比较的是地址</p><h3 id="成员函数" tabindex="-1"><a class="header-anchor" href="#成员函数"><span>成员函数</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//完全一样返回true，不一样返回false</span></span>
<span class="line"><span>boolean equals(String s) </span></span>
<span class="line"><span>//忽略大小写比较</span></span>
<span class="line"><span>boolean equalsIgnoeCase(String s)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//根据索引获取返回字符</span></span>
<span class="line"><span>public char charAt(int index)</span></span>
<span class="line"><span>//返回此字符串的长度</span></span>
<span class="line"><span>public int length()</span></span>
<span class="line"><span>//返回截取字符串，范围[begin,end)</span></span>
<span class="line"><span>String substring(int beginIndex,int endIndex)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="stringbuilder" tabindex="-1"><a class="header-anchor" href="#stringbuilder"><span>StringBuilder</span></a></h1><p>如果要进行很多字符串拼接操作时，前一个字符串和后一个字符串拼接产生新的字符串然后再与后面的字符串拼接会导致性能很慢，而使用StringBuilder本质上是一个容器（相当于字符串数组）就可以将多个字符串一同放到容器中统一拼接性能就很高</p><p>直接打印StringBuilder是属性值而不是像String一样的地址值，这是因为java再底层做了特殊的处理</p><h3 id="构造方法-1" tabindex="-1"><a class="header-anchor" href="#构造方法-1"><span>构造方法</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//创建一个空白可变字符串对象，不含有任何内容public</span></span>
<span class="line"><span>public StringBuilder() </span></span>
<span class="line"><span>//根据字符串的内容，来创建可变字符串对象</span></span>
<span class="line"><span>StringBuilder(String str)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="成员方法" tabindex="-1"><a class="header-anchor" href="#成员方法"><span>成员方法</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//添加数据，并返回对象本身</span></span>
<span class="line"><span>public StringBuilder append(任意类型)</span></span>
<span class="line"><span>//反转容器中的内容 </span></span>
<span class="line"><span>public StringBuilder reverse()</span></span>
<span class="line"><span>//返回长度(字符出现的个数) </span></span>
<span class="line"><span>public int length()</span></span>
<span class="line"><span>//把StringBuilder转换为String</span></span>
<span class="line"><span>public String toString()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="stringjoiner" tabindex="-1"><a class="header-anchor" href="#stringjoiner"><span>StringJoiner</span></a></h1><p>StringJoiner跟StringBuilder一样，也可以看成是一个容器，创建之后里面的内容是可变的。作用：提高字符串的操作效率，而且代码编写特别简洁</p><h3 id="构造函数" tabindex="-1"><a class="header-anchor" href="#构造函数"><span>构造函数</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//创建一个StringJoiner对象，指定拼接时的间隔符号</span></span>
<span class="line"><span>public StringJoiner (间隔符号)</span></span>
<span class="line"><span>//创建一个StringJoiner对象，指定拼接时的间隔符号、开始符号、结束符号</span></span>
<span class="line"><span>public StringJoiner(间隔符号，开始符号，结束符号)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="成员函数-1" tabindex="-1"><a class="header-anchor" href="#成员函数-1"><span>成员函数</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>添加数据，并返回对象本身</span></span>
<span class="line"><span>public StringJoiner add(添加的内容)</span></span>
<span class="line"><span>返回长度（字符出现的个数）</span></span>
<span class="line"><span>public int length()</span></span>
<span class="line"><span>返回一个字符串（该字符串就是拼接之后的结果）</span></span>
<span class="line"><span>public String toString()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="字符串相关类的底层原理" tabindex="-1"><a class="header-anchor" href="#字符串相关类的底层原理"><span>字符串相关类的底层原理</span></a></h1><p>![[Clip_2024-06-23_20-42-36.png]] java8之后会对字符串先进行预估，但预估依旧消耗很多性能</p><h1 id="集合" tabindex="-1"><a class="header-anchor" href="#集合"><span>集合</span></a></h1><p>集合可以自动扩容，无法存基本数据类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ArrayList&lt;String&gt; str=new ArrayList&lt;String&gt;();  </span></span>
<span class="line"><span>ArrayList&lt;String&gt; str=new ArrayList&lt;&gt;();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>添加元素<code>boolean add(E e)</code>,返回当前字符串是否被添加成功</p><p>删除元素<code>bollean remove(E e)</code>,</p><p>修改元素<code>E set(int index,E e)</code>将index位置上的值修改为e的值,并返回该位置原本的值</p><p>查询<code>E get(int index)</code>返回index位置上的元素</p><p>获取长度<code>int size()</code>返回集合的长度</p><h3 id="基本数据类型对应的包装类" tabindex="-1"><a class="header-anchor" href="#基本数据类型对应的包装类"><span>基本数据类型对应的包装类</span></a></h3><table><thead><tr><th>基本数据类型</th><th>对应的包装类</th></tr></thead><tbody><tr><td>byte</td><td>Byte</td></tr><tr><td>short</td><td>Short</td></tr><tr><td>char</td><td>Character</td></tr><tr><td>int</td><td>Integer</td></tr><tr><td>long</td><td>Long</td></tr><tr><td>float</td><td>Float</td></tr><tr><td>double</td><td>Double</td></tr><tr><td>boolean</td><td>Boolean</td></tr></tbody></table><h1 id="单列集合" tabindex="-1"><a class="header-anchor" href="#单列集合"><span>单列集合</span></a></h1><p>![[Clip_2024-10-12_20-00-25.png]] vector已经被淘汰了</p><p>List系列集合：添加的元素是有序可重复、有索引 有序指的是存储的顺序是有序的,而不是按从大到小顺序</p><p>Set系列集合：添加的元素是无序、不重复、无索引</p><p>如果往list中添加数据，那么方法永远返回true，因为List系列的是允许元素重复的。 如果往set中添加数据教据，如果当前要添加元素不存在，方法返回true，表示添加成功。</p><h2 id="collection" tabindex="-1"><a class="header-anchor" href="#collection"><span>Collection</span></a></h2><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public boolean add(E e)</td><td>把给定的对象添加到当前集合中,添加到末尾</td></tr><tr><td>public void clear()</td><td>清空集合中所有的元素</td></tr><tr><td>public boolean remove(E e)</td><td>把给定的对象在当前集合中删除</td></tr><tr><td>public boolean contains(object obj)</td><td>判断当前集合中是否包含给定的对象</td></tr><tr><td>public boolean isEmpty()</td><td>判断当前集合是否为空</td></tr><tr><td>public int size()</td><td>返回集合中元素的个数/集合的长度<br></td></tr></tbody></table><h3 id="迭代器" tabindex="-1"><a class="header-anchor" href="#迭代器"><span>迭代器</span></a></h3><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>Iterator&lt;E&gt; iterator()</td><td>返回迭代器对象，默认指向当前集合的0索引</td></tr><tr><td>boolean hasNext()</td><td>判断当前位置是否有元素，有元素返回true，没有元素返回false</td></tr><tr><td>next()</td><td>获取当前位置的元素并将迭代器对象移向下一个位置。<br></td></tr></tbody></table><p>当迭代器遍历的时候不能用集合的方法<strong>删除</strong>,这样会报并发修改异常,但可以用迭代器的方法<strong>删除</strong> 该迭代器只能用于删除</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Collection&lt;String&gt; coll=new ArrayList&lt;&gt;();</span></span>
<span class="line"><span>Iterator&lt;String&gt; it =coll.iterator();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>while(it.hasNext()){</span></span>
<span class="line"><span>	if(&#39;b&#39;.equals(str)){</span></span>
<span class="line"><span>		coll.remove(&#39;b&#39;);//error</span></span>
<span class="line"><span>		it.remove();//ok</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="list" tabindex="-1"><a class="header-anchor" href="#list"><span>List</span></a></h2><p>Collection的方法List都继承了 List集合因为有索引，所以多了很多索引操作的方法。</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>void add(int index,E element)</td><td>在此集合中的指定位置插入指定的元素</td></tr><tr><td>E remove(int index)</td><td>删除指定索引处的元素，返回被删除的元素</td></tr><tr><td>E set(int index,E element)</td><td>修改指定索引处的元素，返回被修改的元素</td></tr><tr><td>E get(int index)</td><td>返回指定索引处的元素</td></tr></tbody></table><p>当调用重载函数时会优先调用形参和实参一致的方法, 如:使用remove删除integer类型数组中的元素时会优先按索引删除,这是因为list中的rmove的形参是int类型,不需要封装即可直接使用,而Collection中的remove是Object类型,需要封装后使用. 若想要删除指定元素需要进行一次封装</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>List&lt;Integer&gt; list = new ArrayList&lt;&gt;();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>list.remove(1);//删除的是索引为1的方法</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Integer i=Integer.valueOf(1);</span></span>
<span class="line"><span>list.remove(i);//删除值为1的方法</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="迭代器-1" tabindex="-1"><a class="header-anchor" href="#迭代器-1"><span>迭代器</span></a></h3><p>除了本身从collection中继承的迭代器外,list还有自己的迭代器ListIterator 该迭代器能用于删除也能用于添加</p><table><thead><tr><th>方法</th><th>作用</th></tr></thead><tbody><tr><td>void add(E e)</td><td>将指定的元素插入列表（可选操作）。</td></tr><tr><td>boolean hasNext()</td><td>以正向遍历列表时，如果列表迭代器有多个元素，则返回true（换句话说，如果next返回一个元素而不是抛出异常，则返回true）。</td></tr><tr><td>boolean hasPrevious()</td><td>如果以逆向遍历列表，列表迭代器有多个元素，则返回true。</td></tr><tr><td>next()</td><td>返回列表中的下一个元素。</td></tr><tr><td>int nextIndex()</td><td>返回对next的后续调用所返回元素的索引。</td></tr><tr><td>previous()</td><td>列表中的前一个元素。</td></tr><tr><td>int previousIndex()</td><td>返回对previous 的后续调用所返回元素的索引。</td></tr><tr><td>void remove()</td><td>从列表中移除由next或previous 返回的最后一个元素（可选操作）。</td></tr><tr><td>void set(E e)</td><td>用指定元素替换next或previous返回的最后一个元素（可选操作）。</td></tr><tr><td>和hasNext,next一样hasPrevious,previos也是配合使用的,但迭代器默认位置依旧是从0索引开始,因此在使用hasPrevious,previos时需要让迭代器移动到末尾</td><td></td></tr></tbody></table><h2 id="set" tabindex="-1"><a class="header-anchor" href="#set"><span>Set</span></a></h2><ol><li>如果想要集合中的元素可重复用ArrayList集合，基于数组的。（用的最多）</li><li>如果想要集合中的元素可重复，而且当前的增删操作明显多于查询用LinkedList集合，基于链表的。</li><li>如果想对集合中的元素去重用HashSet集合，基于哈希表的。（用的最多）</li><li>如果想对集合中的元素去重，而且保证存取顺序用LinkedHashSet集合，基于哈希表和双链表，效率低于HashSet。</li><li>如果想对集合中的元素进行排序用TreeSet集合，基于红黑树。后续也可以用List集合实现排序。</li></ol><p>无序 不重复 无索引 Collection是单列集合的祖宗接口，它的功能是全部单列集合都可以继承使用的。</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public boolean add(E e)</td><td>把给定的对象添加到当前集合中</td></tr><tr><td>public void clear()</td><td>清空集合中所有的元素</td></tr><tr><td>public boolean remove(E e)</td><td>把给定的对象在当前集合中删除</td></tr><tr><td>public boolean contains(object obj)</td><td>判断当前集合中是否包含给定的对象</td></tr><tr><td>public boolean isEmpty()</td><td>判断当前集合是否为空</td></tr><tr><td>public int size()</td><td>返回集合中元素的个数/集合的长度</td></tr></tbody></table><h3 id="hashset" tabindex="-1"><a class="header-anchor" href="#hashset"><span>HashSet</span></a></h3><p>HashSet集合底层采取哈希表存储数据</p><p>JDK8之前：数组+链表 JDK8开始：数组+链表+红黑树</p><h4 id="哈希值" tabindex="-1"><a class="header-anchor" href="#哈希值"><span>哈希值</span></a></h4><p>根据hashCode方法算出来的int类型的整数 该方法定义在Object类中，所有对象都可以调用，默认使用地址值进行计算 般情况下，会重写hashCode方法，利用对象内部的属性值计算哈希值</p><p>如果发生哈希冲突 JDK8以前：新元素存入数组，老元素挂在新元素下面 JDK8以后：新元素直接挂在老元素下面</p><h3 id="linkedhashset" tabindex="-1"><a class="header-anchor" href="#linkedhashset"><span>LinkedHashSet</span></a></h3><p>有序、不重复、无索引。</p><p>底层数据结构是依然哈希表，只是每个元素又额外的多了一个双链表的机制记录存储的顺序。</p><h3 id="treeset" tabindex="-1"><a class="header-anchor" href="#treeset"><span>TreeSet</span></a></h3><p>不重复、无索引、可排序 可排序：按照元素的默认规则（有小到大）排序。</p><p>TreeSet集合底层是基于红黑树的数据结构实现排序的，增删改查性能都较好。</p><h4 id="treeset的两种比较方式" tabindex="-1"><a class="header-anchor" href="#treeset的两种比较方式"><span>TreeSet的两种比较方式</span></a></h4><ul><li>负数：表示当前要添加的元素是小的，存左边</li><li>正数：表示当前要添加的元素是大的，存右边</li><li>0:表示当前要添加的元素已经存在，舍弃</li></ul><p><strong>默认排序/自然排序：Javabean类实现comparable接口指定比较规则</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class Student implements Comparable&lt;Student2&gt;{</span></span>
<span class="line"><span>	@Override</span></span>
<span class="line"><span>	public int compareTo(Student2 o) { </span></span>
<span class="line"><span>		//判断语文成绩</span></span>
<span class="line"><span>		int i=this-&gt;yuwen_score-o.yuwen_score;</span></span>
<span class="line"><span>		//如果语文成绩一样比较数学成绩</span></span>
<span class="line"><span>		i= i==0 ? this-&gt;shuxue_score - o.shuxue_score:i;</span></span>
<span class="line"><span>		return i;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>比较器排序：创建TreeSet对象时候，传递比较器Comparator指定规则</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>TreeSet&lt;String&gt; ts= new TreeSet&lt;&gt;(new Comparator&lt;String&gt;(){</span></span>
<span class="line"><span>	@Override</span></span>
<span class="line"><span>	public int compare(String o1,String o2）{</span></span>
<span class="line"><span>		//按照长度排序</span></span>
<span class="line"><span>		int i =o1.length()-o2.length();</span></span>
<span class="line"><span>		//如果一样长则按照首字母排序(默认排序)</span></span>
<span class="line"><span>		i = i == θ ? o1.compareTo(o2):i;</span></span>
<span class="line"><span>		return i;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>});</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="双列集合" tabindex="-1"><a class="header-anchor" href="#双列集合"><span>双列集合</span></a></h1><p>![[Clip_2024-10-12_19-31-37.png]]</p><h2 id="map" tabindex="-1"><a class="header-anchor" href="#map"><span>Map</span></a></h2><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>V put(K key,V value)</td><td>添加元素</td></tr><tr><td>V remove(object key)</td><td>根据键删除键值对元素,返回删除的值</td></tr><tr><td>void clear()</td><td>移除所有的键值对元素</td></tr><tr><td>boolean containsKey(object key)</td><td>判断集合是否包含指定的键</td></tr><tr><td>boolean containsValue(object value)</td><td>判断集合是否包含指定的值</td></tr><tr><td>boolean isEmpty()</td><td>判断集合是否为空</td></tr><tr><td>int size()</td><td>集合的长度，也就是集合中键值对的个数</td></tr><tr><td>Set&lt;T t&gt; keySet()</td><td>获取键的集合</td></tr><tr><td>Set&lt;Entry&lt;String,String&gt;&gt; entrySet()</td><td>获取所有键值对对象的集合</td></tr></tbody></table><p>如果添加重复键的话就会把原本的键值覆盖,返回被覆盖的值</p><p>Entry是Map中的一个接口,因此调用的时候需要使用Map.的形式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Set&lt;Map.Entry&lt;String,String&gt;&gt; entries = map.entrySet();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>对于一个Entry对象是一个键值对对象,因此还需要使用getKey()和getValue()获取键和值</p><p><strong>遍历</strong> 每个可遍历的容器都有一个forEach()函数用于遍历,但遍历时需要传入一个函数在该函数中表明对此容器中每个元素的操作 default void forEach(BiConsumer&lt;? super K, ? super V&gt; action)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//lambda表达式</span></span>
<span class="line"><span>map.forEach((String key,String value)-&gt;{</span></span>
<span class="line"><span>		System.out.println(key + &quot;=&quot; + value);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//匿名内部类</span></span>
<span class="line"><span>map.forEach(new BiConsumer&lt;String, String&gt;(){</span></span>
<span class="line"><span>	@Override</span></span>
<span class="line"><span>	public void accept(String key,String value){</span></span>
<span class="line"><span>		System.out.println(key+&quot;&quot;=&quot;+value);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="hashmap" tabindex="-1"><a class="header-anchor" href="#hashmap"><span>HashMap</span></a></h2><p>由键决定：无序、不重复、无索引。</p><p>HashMap是Map里面的一个实现类。没有额外的特有方法，直接使用Map里面的方法就可以了。</p><p>HashMap跟HashSet底层原理是一模一样的天都是哈希表结构 计算的是键的哈希值</p><p>jdk8以前 如果在键对应的位置上已经有元素了在判断值是否一样如果一样就用新值覆盖旧值,如果不一样会把新的键值对添加到哈希数组中,再将旧的键值对使用链地址法挂到新键值对下面形成一个链表</p><p>jdk8之后新元素会之间挂在旧元素下面,当链表的长度超过8且数组长度&gt;=64，自动转成红黑树</p><p>如果键存储的是自定义对象需要重写equals方法,因为在进行插入时是使用equals方法比较的</p><h2 id="linkedhashmap" tabindex="-1"><a class="header-anchor" href="#linkedhashmap"><span>LinkedHashMap</span></a></h2><p>由键决定：有序、不重复、无索引。</p><p>继承自HashMap,没有额外的方法</p><p>有序指的是保证存储和取出的元素顺序一致原理：底层数据结构是依然哈希表，只是每个键值对元素又额外的多了一个双链表的机制记录存储的顺序。</p><h1 id="treemap" tabindex="-1"><a class="header-anchor" href="#treemap"><span>TreeMap</span></a></h1><p>TreeMap跟TreeSet底层原理一样，都是红黑树结构的。 由键决定特性：不重复、无索引、可排序可排序：对键进行排序。 默认按照键的从小到大进行排序，也可以自己规定键的排序规则</p><p><strong>规定排序规则的两种方法</strong></p><ul><li>实现comparable接口，指定比较规则。</li><li>创建集合时传递comparator比较器对象，指定比较规则，</li></ul><h1 id="可变参数" tabindex="-1"><a class="header-anchor" href="#可变参数"><span>可变参数</span></a></h1><p>方法形参的个数是可以发生变化的</p><p>在一个方法的形参中只能有一个可变参数,且必须放在形参列表最后</p><p>将可变参数当作数组使用即可,它底层就是被编译器自动封装成一个数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>属性类型...名字</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int...args</span></span>
<span class="line"><span></span></span>
<span class="line"><span>public static int getSum(int...args){</span></span>
<span class="line"><span>	int sum=0;</span></span>
<span class="line"><span>	for(int i:args){</span></span>
<span class="line"><span>		sum+=i;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	return sum;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="collections" tabindex="-1"><a class="header-anchor" href="#collections"><span>Collections</span></a></h1><p>和Collection不一样它是集合的工具类。</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>public static &lt;T&gt; boolean addAll(Collection&lt;T&gt; c, T... elements)</td><td>批量添加元素</td></tr><tr><td>public static void shuffle(List&lt;?&gt; list)</td><td>打乱List集合元素的顺序</td></tr><tr><td>public static &lt;T&gt; void sort(List&lt;T&gt; list)</td><td>排序</td></tr><tr><td>public static &lt;T&gt; void sort(List&lt;T&gt; list, Comparator&lt;T&gt; c)</td><td>根据指定的规则进行排序</td></tr><tr><td>public static &lt;T&gt; int binarySearch (List&lt;T&gt; list, T key)</td><td>以二分查找法查找元素</td></tr><tr><td>public static &lt;T&gt; void copy(List&lt;T&gt; dest, List&lt;T&gt; src)</td><td>拷贝集合中的元素</td></tr><tr><td>public static &lt;T&gt; int fill (List&lt;T&gt; list, T obj)</td><td>使用指定的元素填充集合</td></tr><tr><td>public static &lt;T&gt; void max/min(Collection&lt;T&gt; coll)</td><td>根据默认的自然排序获取最大/小值</td></tr><tr><td>public static &lt;T&gt; void swap(List&lt;?&gt; list, int i, int j)</td><td>交换集合中指定位置的元素</td></tr></tbody></table><h1 id="不可变集合" tabindex="-1"><a class="header-anchor" href="#不可变集合"><span>不可变集合</span></a></h1><p>如果想要让别人只对一个集合有查询权限而没有修改权限就可以使用不可变集合 在List、Set、Map接口中，都存在静态的of方法，可可以获取一个不可变的集合</p><table><thead><tr><th>方法名称</th><th>说明</th></tr></thead><tbody><tr><td>static &lt;E&gt; List&lt;E&gt; of(E...elements)</td><td>创建一个具有指定元素的List集合对象</td></tr><tr><td>static &lt;E&gt; Set&lt;E&gt; of(E...elements)</td><td>创建一个具有指定元素的Set集合对象</td></tr><tr><td>static &lt;K, V&gt; Map&lt;K, V&gt; of(E...elements)</td><td>创建一个具有指定元素的Map集合对象</td></tr><tr><td>通过这些方法获取到的集合不能添加，不能删除，不能修改</td><td></td></tr></tbody></table>`,108)]))}const p=a(t,[["render",l]]),c=JSON.parse('{"path":"/back/java/2/","title":"2 STL","lang":"zh-CN","frontmatter":{"title":"2 STL","createTime":"2025/04/05 12:12:26","permalink":"/back/java/2/"},"readingTime":{"minutes":13.09,"words":3927},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/2 STL.md","headers":[]}');export{p as comp,c as data};
